protected void onImpact(RayTraceResult result) {
        if (!this.world.isRemote) {
            if (result.entityHit!= null) {
                result.entityHit.attackEntityFrom(DamageSource.causeThrownDamage(this, this.getThrower()), 1.0F);
            }

            if (!this.world.isRemote) {
                if (result.typeOfHit == RayTraceResult.Type.BLOCK) {
                    this.world.setBlockState(result.getBlockPos(), Blocks.END_STONE.getDefaultState());
                } else if (result.typeOfHit == RayTraceResult.Type.ENTITY) {
                    Entity entity = result.entityHit;

                    if (entity instanceof EntityEndermite) {
                        entity.attackEntityFrom(DamageSource.causeThrownDamage(this, this.getThrower()), 1.0F);
                    }
                }

                this.world.playSound(null, this.posX, this.posY, this.posZ, SoundEvents.ENTITY_ENDERPEARL_THROW, this.getSoundCategory(), 1.0F, 1.0F / (this.getRNG().nextFloat() * 0.4F + 1.2F) + 0.5F);

                if (!this.isSilent()) {
                    this.world.playEvent(2001, this.getPosition(), Block.getStateId(Blocks.END_STONE.getDefaultState()));
                }

                if (!this.world.isRemote) {
                    this.setDead();
                }
            }
        }
    }

