public int largestAltitude(int[] gain) {
                int max = 0;
                int cur = 0;
                for (int i = 0; i < gain.length; i++) {
                    cur += gain[i];
                    if (cur > max) {
                        max = cur;
                    }
                    if (i == gain.length - 1) {
                        cur = 0;
                    }
                }
                return max;
            }

