private Map<Class, Integer> getClassIndicesMap(final CreationPlanImpl plan, final FieldIndexValue fieldIndexValue, final Field field) {
        final Map<Class, Integer> classIndexes = new HashMap<>();
        final List<Relation> relations = hierarchyGraph.getAttributeRelations(field.getDeclaringClass());
        for (Relation relation : relations) {
            final Class targetClass = relation.getTargetClass();
            final Field targetField = relation.getTargetField();
            final Object value = fieldIndexValue.getValue();
            final Object transformedValue = NumberUtil.castNumber(targetField.getType(), value);
            final Object byId = findById(targetClass, transformedValue);
            if (byId == null) {
                throw new IllegalArgumentException("Element not found with id: " + value
                        + ", Class: " + targetClass);
            }
            classIndexes.put(targetClass, byId);
        }
        return classIndexes;
    }

