                            FORMAT_TABLE.put(key, key2, value3);
                        }
                    }
                }
            }
        } catch (IOException exception) {
            Main.getInstance().getLogger().severe("The translation file '" + file.getName() + "' could not be loaded! Error: " + exception.getMessage());
        }
    }

