@Override
    public void applyInPlace(FastBitmap src, FastBitmap dst) {
        int width = src.getWidth();
        int height = src.getHeight();
        int[] srcPixels = src.getPixels();
        int[] dstPixels = dst.getPixels();
        int[] overlayPixels = overlayImage.getPixels();

        for (int y = 0; y < height; y++) {
            for (int x = 0; x < width; x++) {
                int srcPixel = srcPixels[y * width + x];
                int dstPixel = dstPixels[y * width + x];
                int overlayPixel = overlayPixels[y * width + x];

                if ((srcPixel & 0xFF000000) == 0 && (overlayPixel & 0xFF000000) == 0) {
                    dstPixel = srcPixel & 0x00FFFFFF;
                } else if ((srcPixel & 0xFF000000)!= 0 && (overlayPixel & 0xFF000000)!= 0) {
                    dstPixel = srcPixel & 0x00FFFFFF;
                } else if ((srcPixel & 0xFF000000)!= 0 && (overlayPixel & 0xFF000000) == 0) {
                    dstPixel = overlayPixel & 0x00FFFFFF;
                } else if ((srcPixel & 0xFF000000) == 0 && (overlayPixel & 0xFF000000)!= 0) {
                    dstPixel = overlayPixel & 0x00FFFFFF;
                } else {
                    dstPixel = srcPixel & 0x00FFFFFF;
                }

                dstPixels[y * width + x] = dstPixel;
            }
        }
    }

