	public void execute(@NotNull String[] args) {
		if (args.length == 0) {
			GroupManager.getInstance().getMessenger().sendMessage(Messages.get("manworld.usage"));
			return;
		}
		if (args[0].equalsIgnoreCase("list")) {
			GroupManager.getInstance().getMessenger().sendMessage(Messages.get("manworld.list"));
			return;
		}
		if (args[0].equalsIgnoreCase("add")) {
			if (args.length < 2) {
				GroupManager.getInstance().getMessenger().sendMessage(Messages.get("manworld.usage"));
				return;
			}
			GroupManager.getInstance().getMessenger().sendMessage(Messages.get("manworld.add", args[1]));
			return;
		}
		if (args[0].equalsIgnoreCase("remove")) {
			if (args.length < 2) {
				GroupManager.getInstance().getMessenger().sendMessage(Messages.get("manworld.usage"));
				return;
			}
			GroupManager.getInstance().getMessenger().sendMessage(Messages.get("manworld.remove", args[1]));
			return;
		}
		if (args[0].equalsIgnoreCase("reload")) {
			GroupManager.getInstance().getMessenger().sendMessage(Messages.get("manworld.reload"));
			return;
		}
		GroupManager.getInstance().getMessenger().sendMessage(Messages.get("manworld.usage"));
	}

