@Override
    public Optional<ResultSet> retrieve(ReducedDiscoveryMessage message, Page page) throws GSException {

	Optional<String> request = createRequest(message, page);

	if (!request.isPresent()) {

	    logger.warn("Invalid request");
	    return Optional.empty();
	}

	logger.trace("Retrieving results");

	HttpResponse<InputStream> response = executeGet(request.get());

	logger.trace("Retrieved results");

	return Optional.of(toResultSet(response));
    }

