            bb.readBytes(subobjBytes);
            List<Subobject> subobjects = new ArrayList<>();
            while (bb.readableBytes() > 0) {
                Subobject subobject = subobjReg.readFrom(bb);
                subobjects.add(subobject);
            }
            readFromBytes(subobjBytes, subobjects);
        }

