@Override
        public boolean onCommand(CommandSender sender, Command command, String label, String[] args) {
            if (!(sender instanceof Player)) {
                sender.sendMessage(Colors.RED + "You must be a player to use this command!");
                return true;
            }
            Player player = (Player) sender;
            if (args.length == 0) {
                List<CoreProfile> profiles = plugin.getProfiles();
                List<String> names = new ArrayList<>();
                for (CoreProfile profile : profiles) {
                    names.add(profile.getName());
                }
                Collections.sort(names);
                for (String name : names) {
                    player.sendMessage(Colors.GREEN + name);
                }
                return true;
            }
            if (args.length == 1) {
                UUID uuid = plugin.getProfile(args[0]).getUuid();
                if (uuid == null) {
                    player.sendMessage(Colors.RED + "That player does not exist!");
                    return true;
                }
                List<CoreProfile> profiles = plugin.getProfiles();
                List<String> names = new ArrayList<>();
                for (CoreProfile profile : profiles) {
                    if (profile.getUuid().equals(uuid)) {
                        names.add(profile.getName());
                    }
                }
                Collections.sort(names);
                for (String name : names) {
                    player.sendMessage(Colors.GREEN + name);
                }
                return true;
            }
            if (args.length == 2) {
                UUID uuid = plugin.getProfile(args[0]).getUuid();
                if (uuid == null) {
                    player.sendMessage(Colors.RED + "That player does not exist!");
                    return true;
                }
                Rank rank = plugin.getRank(args[1]);
                if (rank == null) {
                    player.sendMessage(Colors.RED + "That rank does not exist!");
                    return true;
                }
                List<CoreProfile> profiles = plugin.getProfiles();
                List<String> names = new ArrayList<>();
                for (CoreProfile profile : profiles) {
                    if (profile.getUuid().equals(uuid) && profile.getRank().equals(rank)) {
                        names.add(profile.getName());
                    }
                }
                Collections.sort(names);
                for (String name : names) {
                    player.sendMessage(Colors.GREEN + name);
                }
                return true;
            }
            return false;
        }

