@Override
    public List<Annotation> validate(final Annotation annotation, final IIssueCallback callback) {
        final List<Annotation> issues = super.validate(annotation, callback);
        if (issues.isEmpty()) {
            final ValueReference item = (ValueReference) annotation.getParameter(ITEM_PARAMETER);
            final String label = (String) annotation.getParameter(LABEL_PARAMETER);
            final String hierarchy = (String) annotation.getParameter(HIERARCHY_PARAMETER);
            final HierarchyPolicy policy = HierarchyPolicy.valueOf(hierarchy);
            if (policy == HierarchyPolicy.ALWAYS) {
                return issues;
            }
            final StringValue labelValue = PatternLanguageHelper.createStringValue(label);
            final StringValue itemValue = PatternLanguageHelper.createStringValue(item.getValue());
            final List<Annotation> itemAnnotations = PatternLanguageHelper.getAnnotation(itemValue, PatternLanguagePackage.Literals.VALUE_REFERENCE__ANNOTATION);
            if (itemAnnotations.isEmpty()) {
                callback.addIssue(HIERARCHY_LITERAL_ISSUE, itemValue, labelValue);
            } else {
                final List<Annotation> hierarchyAnnotations = itemAnnotations.stream().filter(a -> a.getParameter(LABEL_PARAMETER)!= null).collect(Collectors.toList());
                if (hierarchyAnnotations.isEmpty()) {
                    callback.addIssue(HIERARCHY_LITERAL_ISSUE, itemValue, labelValue);
                } else {
                    final List<Annotation> hierarchyAnnotationValues = hierarchyAnnotations.stream().map(a -> (StringValue) a.getParameter(LABEL_PARAMETER)).collect(Collectors.toList());
                    if (hierarchyAnnotationValues.contains(labelValue)) {
                        callback.addIssue(HIERARCHY_LITERAL_ISSUE, itemValue, labelValue);
                    }
                }
            }
        }
        return issues;
    }

