private List enumerateThreads(Map classLoaderMap) {
        List threads = new ArrayList();
        for (int i = 0; i < classLoaderMap.size(); i++) {
            String key = (String) classLoaderMap.keySet().toArray()[i];
            String name = (String) classLoaderMap.values().toArray()[i];
            Map threadMap = Instruments.getThreadMap(key);
            for (int j = 0; j < threadMap.size(); j++) {
                ThreadModel thread = new ThreadModel();
                thread.setThreadName((String) threadMap.keySet().toArray()[j]);
                thread.setThreadState((String) threadMap.values().toArray()[j]);
                thread.setThreadGroup(name);
                threads.add(thread);
            }
        }
        return threads;
    }

