@Override
    public void execute(HttpServletRequest request) {
        try {
            ResteasyProviderFactory.getInstance().injectProperties(request);
            RestConfiguration config = RestConfiguration.getInstance();
            Metadata metadata = config.getMetadata();
            EntityMetadata entityMetadata = metadata.getEntity(entity);
            if (entityMetadata == null) {
                throw new IllegalArgumentException("Entity " + entity + " not found");
            }
            FieldTreeNode fieldTreeNode = entityMetadata.getField(field);
            if (fieldTreeNode == null) {
                throw new IllegalArgumentException("Field " + field + " not found");
            }
            if (!(fieldTreeNode instanceof SimpleField)) {
                throw new IllegalArgumentException("Field " + field + " is not a simple field");
            }
            SimpleField simpleField = (SimpleField) fieldTreeNode;
            if (!simpleField.isGenerated()) {
                throw new IllegalArgumentException("Field " + field + " is not generated");
            }
            if (simpleField.getGenerator() == null) {
                throw new IllegalArgumentException("Field " + field + " has no generator");
            }
            GeneratedFields generatedFields = simpleField.getGenerator().generate(n);
            ArrayNode result = JsonNodeFactory.instance.arrayNode();
            for (int i = 0; i < n; i++) {
                JsonNode node = generatedFields.get(i);
                result.add(node);
            }
            sendResponse(result, request);
        } catch (Exception e) {
            LOGGER.error("Error generating data", e);
            sendError(e, request);
        }
    }

