prediction:
@Override
    public Object send(SocketMessage message) throws RemotingException {
        int retryTimes = 0;
        while (retryTimes++ < RETRY_TIMES) {
            try {
                return super.send(message);
            } catch (RemotingException e) {
                if (retryTimes == RETRY_TIMES) {
                    throw e;
                }
                SocketLog.warn("send message failed, retryTimes:{}", retryTimes);
                retry(message, retryTimes);
            }
        }
        return null;
    }

